get_p &lt;- function(outcome_col, w) {
  if (w == 0) return(NA_real_)
  test &lt;- tryCatch(
    cmh_test_at_week(fu_with_strata, outcome_col, w),
    error = function(e) NULL
  )
  if (is.null(test)) NA_real_ else test$p.value
}

